import math

# Given strikes and implied volatilities
K = [800, 850, 900, 950, 1000, 1050, 1100, 1150, 1200]
iv = [0.20, 0.205, 0.21, 0.215, 0.22, 0.225, 0.23, 0.235, 0.24]

# Assumptions from Example 26.4 (commonly used setup):
F = 1000.0          # forward/spot level used as pivot in the example
r = 0.0             # discounting ignored in the example
T = 1.0             # 1 year
notional = 100_000_000.0  # $100 million variance notional (so output is in $ millions)

# Black-Scholes undiscounted call/put prices from implied vol
def n_cdf(x):
    return 0.5 * (1.0 + math.erf(x / math.sqrt(2.0)))

def bs_call_undiscounted(F, K, sigma, T):
    if sigma <= 0 or T <= 0:
        return max(F - K, 0.0)
    vol_sqrt = sigma * math.sqrt(T)
    d1 = (math.log(F / K) + 0.5 * sigma * sigma * T) / vol_sqrt
    d2 = d1 - vol_sqrt
    return F * n_cdf(d1) - K * n_cdf(d2)

def bs_put_undiscounted(F, K, sigma, T):
    if sigma <= 0 or T <= 0:
        return max(K - F, 0.0)
    vol_sqrt = sigma * math.sqrt(T)
    d1 = (math.log(F / K) + 0.5 * sigma * sigma * T) / vol_sqrt
    d2 = d1 - vol_sqrt
    return K * n_cdf(-d2) - F * n_cdf(-d1)

# Compute option prices for each strike using the provided implied vols
prices = []
for Ki, si in zip(K, iv):
    if Ki < F:
        prices.append(bs_put_undiscounted(F, Ki, si, T))
    else:
        prices.append(bs_call_undiscounted(F, Ki, si, T))

# Approximate fair variance strike using discrete replication formula:
# K_var = (2/T) * sum_i [ (ΔK / K_i^2) * Q(K_i) ]
# Using trapezoidal spacing weights with ΔK_i = (K_{i+1} - K_{i-1})/2 for interior,
# and one-sided for endpoints.
dK = []
n = len(K)
for i in range(n):
    if i == 0:
        dK.append(K[1] - K[0])
    elif i == n - 1:
        dK.append(K[-1] - K[-2])
    else:
        dK.append(0.5 * (K[i+1] - K[i-1]))

K_var = (2.0 / T) * sum((dK[i] * prices[i]) / (K[i] ** 2) for i in range(n))

# Value of variance swap at inception is zero; question asks for "value"
# in the example context (often interpreted as the variance strike times notional).
value_dollars = K_var * notional
value_millions = value_dollars / 1_000_000.0

print(value_millions)

