sigma = [0.20, 0.205, 0.21, 0.215, 0.22, 0.225, 0.23, 0.235, 0.24]

# Assumptions from Example 26.4 (variance swap via log-contract replication)
F = 1000.0      # forward price
r = 0.0         # risk-free rate (continuously compounded)
T = 1.0         # time to maturity in years
notional_musd = 1.0  # variance notional in million dollars (unit requested)

# Black-Scholes undiscounted option prices (since r=0, discount factor = 1)
def bs_call(F, K, sig, T):
    if sig <= 0 or T <= 0:
        return max(F - K, 0.0)
    vol_sqrt = sig * math.sqrt(T)
    d1 = (math.log(F / K) + 0.5 * sig * sig * T) / vol_sqrt
    d2 = d1 - vol_sqrt
    N = lambda x: 0.5 * (1.0 + math.erf(x / math.sqrt(2.0)))
    return F * N(d1) - K * N(d2)

def bs_put(F, K, sig, T):
    if sig <= 0 or T <= 0:
        return max(K - F, 0.0)
    vol_sqrt = sig * math.sqrt(T)
    d1 = (math.log(F / K) + 0.5 * sig * sig * T) / vol_sqrt
    d2 = d1 - vol_sqrt
    N = lambda x: 0.5 * (1.0 + math.erf(x / math.sqrt(2.0)))
    return K * N(-d2) - F * N(-d1)

# Compute option prices: use puts for K <= F, calls for K > F
Q = []
for Ki, si in zip(K, sigma):
    if Ki <= F:
        Q.append(bs_put(F, Ki, si, T))
    else:
        Q.append(bs_call(F, Ki, si, T))

# Discrete approximation of variance swap fair variance:
# K_var = (2/T) * sum_i [ (ΔK_i / K_i^2) * Q(K_i) ]
# with ΔK_i = (K_{i+1}-K_{i-1})/2 for interior, and one-sided for ends
dK = []
n = len(K)
for i in range(n):
    if i == 0:
        dK.append(K[1] - K[0])
    elif i == n - 1:
        dK.append(K[-1] - K[-2])
    else:
        dK.append(0.5 * (K[i+1] - K[i-1]))

K_var = (2.0 / T) * sum((dK[i] / (K[i] ** 2)) * Q[i] for i in range(n))

# Value of variance swap at inception with strike = 0 is notional * fair variance
value_musd = notional_musd * K_var

