import math

par = 1000.0
coupon_rate = 0.084
price = 0.955 * par
years = 9
n = years * 2
c = coupon_rate * par / 2

def bond_price(r):
    return sum(c / ((1 + r) ** t) for t in range(1, n + 1)) + par / ((1 + r) ** n)

lo, hi = 0.0, 1.0
while bond_price(hi) > price:
    hi *= 2

for _ in range(200):
    mid = (lo + hi) / 2
    if bond_price(mid) > price:
        lo = mid
    else:
        hi = mid

ytm = 2 * (lo + hi) / 2
print(f"{ytm:.6f}")

